// Combine All Business Dimensions for Postgres
// This merges Overview, Contact, Social, Rating, PopularTimes into single JSONB object

const executionId = $('Store Execution ID').first().json.execution_id;

// Get data from merged upstream nodes
return items.map(item => {
  const d = item.json;

  return {
    json: {
      execution_id: executionId,
      business_name: d.title || 'Unknown',
      search_string: d.searchString || null,
      apify_place_id: d.url || `${d.title}-${Date.now()}`,

      // Single JSONB object with all dimensions
      business_data: {
        overview: {
          title: d.title,
          category: d.categoryName,
          searchString: d.searchString,
          url: d.url,
          city: d.city,
          state: d.state,
          street: d.street,
          postalCode: d.postalCode,
          countryCode: d.countryCode,
          plusCode: d.plusCode,
          isAdvertisement: d.isAdvertisement,
          rank: d.rank,
          searchPageUrl: d.searchPageUrl,
          temporarilyClosed: d.temporarilyClosed,
          permanentlyClosed: d.permanentlyClosed
        },
        contact: {
          phone: d.phone,
          phoneUnformatted: d.phoneUnformatted,
          website: d.website,
          email: d.email,
          claimThisBusiness: d.claimThisBusiness,
          menu: d.menu
        },
        social: {
          facebookPages: d.facebookPages,
          instagrams: d.instagrams,
          twitters: d.twitters,
          linkedIns: d.linkedIns,
          pinterests: d.pinterests,
          youtubes: d.youtubes
        },
        rating: {
          totalScore: d.totalScore,
          reviewsCount: d.reviewsCount,
          reviewsDistribution: d.reviewsDistribution
        },
        popular_times: {
          popularTimesHistogram: d.popularTimesHistogram
        },
        tags: d.tags || [],
        lead_enrichment: {
          gadId: d.gadId,
          placeId: d.placeId,
          cid: d.cid,
          dataId: d.dataId,
          price: d.price,
          location: d.location
        },
        scraped_at: new Date().toISOString()
      }
    }
  };
});

// Prepare Reviews for Postgres Insert
// Flattens reviews from all places + adds business_id reference

const executionId = $('Store Execution ID').first().json.execution_id;
const results = [];

for (const item of items) {
  const p = item.json;

  // Get business_id from Upsert Business node
  const businessRecord = $('Upsert Business').all().find(b =>
    b.json.business_name === p.title ||
    b.json.apify_place_id === p.url
  );

  const businessId = businessRecord?.json.id;

  if (!businessId) {
    console.log(`Warning: No business_id found for ${p.title}`);
    continue;
  }

  // Ensure reviews exist
  if (Array.isArray(p.reviews) && p.reviews.length > 0) {
    for (const r of p.reviews) {
      results.push({
        json: {
          business_id: businessId,
          // Store entire review as JSONB
          review_data: JSON.stringify({
            placeName: p.title,
            reviewerId: r.reviewerId,
            reviewerUrl: r.reviewerUrl,
            reviewerName: r.name,
            reviewerNumberOfReviews: r.reviewerNumberOfReviews,
            isLocalGuide: r.isLocalGuide,
            stars: r.stars,
            text: r.text,
            textTranslated: r.textTranslated,
            publishAt: r.publishAt,
            publishedAtDate: r.publishedAtDate,
            likesCount: r.likesCount,
            reviewId: r.reviewId,
            reviewUrl: r.reviewUrl,
            reviewImageUrls: r.reviewImageUrls,
            responseFromOwnerDate: r.responseFromOwnerDate,
            responseFromOwnerText: r.responseFromOwnerText
          })
        }
      });
    }
  }
}

return results;
